final:
module binary_counter(
	input clk,
	input reset_n,
	input enable,
	output reg [2:0] count);

always @(posedge clk or negedge reset_n)
	if (!reset_n)
		count <= 0;
	else if (enable)
		count <= count + 1;

  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
